tool_calls.cmd:
cd $WORKSPACE_DIR && ls -la output/h1b-issue-memo.docx && echo "--- validation ---" && python3 skills/docx/scripts/validate.py output/h1b-issue-memo.docx && echo "--- word count (approx) ---" && python3 -c "
import docx
d=docx.Document('output/h1b-issue-memo.docx')
wc=sum(len(p.text.split()) for p in d.paragraphs)
for tb in d.tables:
    for r in tb.rows:
        for c in r.cells:
            wc+=len(c.text.split())
print('Approx words:', wc)
"
